//提交后台数据时执行的检查或附加数据处理
function do_pos_before_CRM_COM() {
    var cfgs = [{
        id: "CRM_COM_NAME",
        name: "公司名称",
        must: true
    }, {
        id: "AUS_CONTACT",
        name: "联系人"
    }, {
        id: "CRM_COM_TELE",
        name: "电话",
        must: true
    }, {
        id: "CRM_COM_ADDR",
        name: "公司地址",
        must: true
    }, {
        id: "CRM_COM_SNAME",
        name: "类别"
    }, {
        id: "CRM_COM_NOTE",
        name: "备注"
    }];
    for (var i = 0; i < cfgs.length; i++) {
        var cfg = cfgs[i];
        cfg.data = [];
    }

    var tb = $('#EWA_FRAME_@SYS_FRAME_UNID');
    var SALES_ID = tb.find("#SALES_ID").val();
    if (!SALES_ID) {
        alert('选择销售');
        return;
    }
    if (EWA.F.FOS["@SYS_FRAME_UNID"]._IMPORT) {
        alert('数据已经提交请关闭并，重新打开窗口');
        return;
    }

    EWA.F.FOS["@SYS_FRAME_UNID"]._IMPORT = true;
    var tempids = [];
    // 粘贴处
    var docbody = tb.find('.ewa-row-content iframe:eq(0)')[0].contentWindow.frames[0].document.body;
    $(docbody).find('table tr:gt(0)').each(function(index) {
        var tmpId = EWA_Utils.tempId("CRM_IMPORT");
        $(this).attr('id', tmpId);
        tempids.push(tmpId);
        for (var i = 0; i < cfgs.length; i++) {
            var cfg = cfgs[i];
            var v = this.cells[i] ? this.cells[i].innerText : "";
            v = v.replace(/`/ig, '').trim();
            cfg.data.push(v);
        }
    });


    var PostAddData = {
        tempids: tempids.join('`')
    };
    for (var i = 0; i < cfgs.length; i++) {
        var cfg = cfgs[i];
        PostAddData[cfg.id + "S"] = cfg.data.join('`');
    }


    EWA.F.FOS["@SYS_FRAME_UNID"].__OK = false;
    console.log(PostAddData);
    $Tip('提交数据...', function() {
        return EWA.F.FOS["@SYS_FRAME_UNID"].__OK;
    });
    var u = "@EWA.CP/business/sales/crm-com-imports.jsp?import=yes&SALES_ID=" + SALES_ID;
    $JP(u, PostAddData, function(rst) {
        EWA.F.FOS["@SYS_FRAME_UNID"].__OK = true;
        var incnew = 0;
        var increpeat = 0;
        for (var n in rst) {
            var imported = rst[n];
            if (n == 'RST') {
                continue;
            }
            if (!imported) { //重复
                $(docbody).find('#' + n + ' td:eq(0)').prepend("【重复】").css('color', 'red');
                increpeat++;
            } else {
                $(docbody).find('#' + n).hide();
                incnew++;
            }
        }
        alert('导入' + incnew + '记录，' + increpeat + '重复');
    });

    return false;
}

function loadCitys() {
    var tb = $('#EWA_FRAME_@SYS_FRAME_UNID');
    var PROVINCE_ID = tb.find("#PROVINCE_ID").val();
    var url = EWA.F.FOS["@SYS_FRAME_UNID"].Url;
    var u1 = new EWA_UrlClass();
    u1.SetUrl(url);
    u1.AddParameter("ewa_action", "loadCitys");
    u1.AddParameter("ewa_ajax", "json");
    u1.AddParameter("PROVINCE_ID", PROVINCE_ID);

    var u = u1.GetUrl();
    $J(u, tb.find("#CITY_ID")[0], 'CITY_NAME', 'CITY_ID', true, null, function(e) {

    });
}

(function() {
    //提交后台数据时执行的检查或附加数据处理
    EWA.F.FOS["@SYS_FRAME_UNID"].DoPostBefore = do_pos_before_CRM_COM;
    EWA.F.FOS["@SYS_FRAME_UNID"]._IMPORT = false;


    var tb = $('#EWA_FRAME_@SYS_FRAME_UNID');
    var down = "<table style='height:20px;float:left'><tr><td><img height=20 src='/EmpScriptV2/EWA_STYLE/images/file_png/XCEL.png'></td>" +
        "<td><a  href='/static/prj/pf/doc-template/CrmImportTemplate.xls' target=_blank>导入模板下载.xls</a></td></tr></table>";
    tb.find(".EWA_TD_B").prepend(down);




})();

