INSERT INTO CRM_COM ( SUP_ID, CRM_COM_NAME,CRM_COM_SNAME,CRM_COM_CODE, ARE_ID, CRM_COM_ARE_DES , CRM_COM_ADDR, CRM_COM_ZIP, CRM_COM_EMAIL, CRM_COM_TELE, CRM_COM_MOBILE , CRM_COM_SIZE_TAG, CRM_COM_TYPE_TAG, CRM_COM_CAL_TAG, CRM_COM_CDATE , CRM_COM_MDATE, CRM_COM_STATE, CRM_COM_SALE, CRM_COM_NOTE, ADM_ID ,ser_tag1,city_id1,CEM_COM_HTTP, CRM_COM_UNID,CRM_COM_FAX ) VALUES ( 3, @CRM_COM_NAME,@CRM_COM_SNAME, @CRM_COM_CODE, @ARE_ID, @CRM_COM_ARE_DES , @CRM_COM_ADDR, @CRM_COM_ZIP, @CRM_CUS_EMAIL, @CRM_CUS_MOBILE, @CRM_CUS_MOBILE , @CRM_COM_SIZE_TAG, @CRM_COM_TYPE_TAG, @CRM_COM_CAL_TAG, getdate() , @CRM_COM_MDATE, @CRM_COM_STATE, @CRM_COM_SALE, @CRM_COM_NOTE, @def_adm_id ,@SER_TAG1,@CITY_ID1, @CEM_COM_HTTP , @SYS_UNID, @CRM_COM_FAX ) -- auto CRM_COM_ID ;
--添加联系人 INSERT INTO CRM_CUS ( CRM_COM_ID, SUP_ID, CRM_CUS_NAME, CRM_CUS_TITLE , CRM_CUS_EMAIL, CRM_CUS_TELE, CRM_CUS_MOBILE , CRM_CUS_CDATE, CRM_CUS_CNUM, CRM_CUS_MASTER , ADM_ID ) SELECT CRM_COM_ID, SUP_ID, @CRM_CUS_NAME, @CRM_CUS_TITLE , @CRM_CUS_EMAIL, @CRM_CUS_MOBILE, @CRM_CUS_MOBILE , @sys_DATE, 0, 'COM_YES', ADM_ID FROM CRM_COM WHERE CRM_COM_ID=@CRM_COM_ID -- auto CRM_CUS_ID ;
INSERT INTO SUP_MAIN ( SUP_NAME,SUP_TAG, SUP_ADDR, SUP_TELE, SUP_EMAIL, SUP_MOBILE , SUP_MEMO,SER_TAG1,CITY_ID1,SUP_ARE_DES,sup_http, SUP_UNID , SUP_FAX ) select CRM_COM_NAME, CRM_COM_SNAME, CRM_COM_ADDR, CRM_COM_TELE, CRM_COM_EMAIL, CRM_COM_MOBILE , CRM_COM_NOTE,SER_TAG1,CITY_ID1, CRM_COM_ARE_DES, CEM_COM_HTTP,@REF_UNID , CRM_COM_FAX FROM CRM_COM WHERE CRM_COM_ID=@CRM_COM_ID -- auto new_SUP_ID ;
INSERT INTO CRM_CONN(SUP_UP_ID,SUP_DOWN_ID,CRM_COM_ID,ADM_ID,CRM_CONN_TAG) VALUES(3, @new_SUP_ID, @CRM_COM_ID, @def_adm_id, 'SUP_TYPE_CUS') ;

