}

function modifyCrmCom(id, name) {
    if ("@y2019" == "1") {
        var u = "@EWA.CP/robert/r_crm2.jsp?T=10&crm_com_id="+id;
        if(top!=window && top.AddTab){
            top.AddTab(u, name);
        } else {
            window.open(u);
        }
        return;
    }
    if ("@ewa_ajax" == 'INSTALL') {
        var u = 'combine_crm.jsp?XML=crm_detail.xml&CRM_COM_ID=' + id;
        window.location = u;
    } else {
        EWA.UI.Dialog.OpenReloadClose('@sys_frame_unid', '@xmlname', 'CRM_COM.Frame.NewModify',
            false, 'CRM_COM_ID=' + id + '&EWA_MTYPE=M')
    }

}

