/**
 * Frame 提交前进行检查，返回true，则可以提交数据
 * 同时可以手动增加提交的参数
 **/
EWA.F.FOS["@sys_frame_unid"].ReloadAfter = function() {
    // this.Merge('fromId','toId'); //合并单元格
    // var exp="@@aa <h1>@@bb</h1> <div>@@cc</div>";
    // this.MergeExp('toId', exp); //合并多个单元格
    var c = this;
    $('#EWA_LF_@SYS_FRAME_UNID input[type=checkbox]').on('click', function() {
        var u1 = new EWA_UrlClass(c.Url);
        u1.AddParameter("xmlname", "/business/common/common.xml");
        u1.AddParameter("itemname", "WEB_FAV_MAIN.F.N");
        u1.AddParameter("EWA_ACTION", "OnPagePost");
        u1.AddParameter("EWA_AJAX", "JSON");

        u1.AddParameter("REF_TAG", "CRM_COM");
        u1.AddParameter("REF_ID", $(this).parent().attr('crm_com_id'));
        u1.AddParameter("FAV_URL", location.href);

        var u = u1.GetUrl();
        $J1(u, function(rst) {
            // console.log(rst);
        });
    });
    $('#EWA_LF_@SYS_FRAME_UNID input[type=checkbox]').each(function() {
        if ($(this).parent().attr('fav_id')) {
            this.checked = true;
        }
    });
};


(function() {
    EWA.F.FOS["@sys_frame_unid"].ReloadAfter();
})();

