(function() {
    //提交后台数据时执行的检查或附加数据处理
    EWA.F.FOS["@SYS_FRAME_UNID"].DoPostBefore = function(){
        var cfgs = [{
            "id": "AUS_PAYDAYS",
            "name": "搜索关键词",
            "length":50
        },{
            "id": "AUS_STATEORPROVINCE",
            "name": "省/直辖市",
            "length":50
        },{
            "id": "CRM_COM_NAME",
            "name": "机构名称",
            "length":200,
            "must": true
        }, {
            "id": "CRM_COM_ADDR",
            "name": "地址",
            "length":500
        }, {
            "id": "AUS_CONTACT",
            "name": "联系人",
            "length":50
        }, {
            "id": "CRM_COM_TELE",
            "name": "电话",
            "length":100
        }, {
            "id": "CRM_COM_MOBILE",
            "name": "手机",
            "length":50
        }, {
            "id": "CRM_COM_EMAIL",
            "name": "邮箱",
            "length":100
        }, {
            "id": "CEM_COM_HTTP",
            "name": "网址",
            "length":1000
        }, {
            "id": "CRM_COM_NOTE",
            "name": "其他情况说明"
        }];

        var tb = $('#EWA_FRAME_@SYS_FRAME_UNID');
        var SALES_ID = tb.find("#SALES_ID").val();
        if (!SALES_ID) {
            $Tip('请选择采集人');
            return;
        }
        let leadSource=getObj("#AUS_TYPE").val();
        if(!leadSource){
            $Tip('请选择线索来源');
            return;
        }
        if (EWA.F.FOS["@SYS_FRAME_UNID"]._IMPORT) {
            $Tip('数据已经提交，请等待或关闭当前窗口稍后再刷新列表');
            return;
        }

        // 粘贴处
        var docbody = tb.find('.ewa-row-content iframe:eq(0)')[0].contentWindow.frames[0].document.body;

        let datas=[];
        let idx = 0;
        let errs = [];
        $(docbody).find("table>tbody:eq(0)").children("tr:gt(0)").each(function(){
            let tds=$(this).children("td");
            let row={};
            let contacts=[];
            let mobiles=[];
            for(let i=0;i<cfgs.length;i++){
                let cfg=cfgs[i];
                let v = this.cells[i] ? this.cells[i].innerText : "";
                if((cfg.id=="AUS_CONTACT" || cfg.id=="CRM_COM_MOBILE") && v.indexOf("、")>0){
                    let arr = v.split("、");
                    if(cfg.id=="AUS_CONTACT"){
                        contacts = arr;
                    }else{
                        mobiles = arr;
                    }
                    v = arr[0];
                }
                row[cfg.id]=v;
                if(cfg["length"] && v.length>cfg["length"]){
                    errs.push("第"+(idx+1)+"行，【"+cfg.name+"】内容长度超过"+cfg["length"]+"，不能导入");
                }
            }
            if(mobiles.length>1){
                row["OTHER_CONTACTS"]=[];
                for(let i=1;i<mobiles.length;i++){
                   let mobile=mobiles[i];
                   let contact=contacts[i]||"未知";
                   row["OTHER_CONTACTS"].push({"CONTACT":contact,"MOBILE":mobile});
                }
            }

            $(this).attr("id","row_"+(idx++));
            datas.push(row);
        });
        if(datas.length==0){
            $Tip("没有数据啊");
            return;
        }
        if(errs.length>0){
            let h="<div style='width:600px;height:400px;overflow:auto;'>";
            h+=errs.join("<br>");
            h+="</div>";
            $DialogHtml(h,"错误","620px","420px");
            return;
        }

        EWA.F.FOS["@SYS_FRAME_UNID"]._IMPORT = true;

        var PostAddData = {
            datas: JSON.stringify(datas),
            cfgs: JSON.stringify(cfgs)
        };


        EWA.F.FOS["@SYS_FRAME_UNID"].__OK = false;

        $Tip('提交数据...', function() {
            return EWA.F.FOS["@SYS_FRAME_UNID"].__OK;
        });

        var u = "@EWA.CP/business/sales/customer-leads-import.jsp?import=yes&SALES_ID=" + SALES_ID;
        u+= "&AUS_TYPE="+leadSource;
        let provinceId=getObj("PROVINCE_ID").val();
        if(provinceId){
            u+="&PROVINCE_ID="+provinceId;
        }
        $JP(u, PostAddData, function(rst) {
            EWA.F.FOS["@SYS_FRAME_UNID"].__OK = true;

            EWA.OW.Load();
            EWA.OW.PWin.EWA.F.FOS["@EWA_PARENT_FRAME"].Reload();

            var incnew = 0;
            var increpeat = 0;
            for (var n in rst) {
                var imported = rst[n];
                if (n == 'RST') {
                    continue;
                }
                if (!imported) { //重复
                    $(docbody).find('#' + n + ' td:eq(2)').prepend("【重复】").css('color', 'red');
                    increpeat++;
                } else {
                    $(docbody).find('#' + n).hide();
                    incnew++;
                }
            }

            alert('导入' + incnew + '记录，' + increpeat + '重复');
        });

        return false;
    }
    EWA.F.FOS["@SYS_FRAME_UNID"]._IMPORT = false;

    function getObj(exp) {
        return $('#f_@sys_frame_unid').find(exp);
    }


    var tb = $('#EWA_FRAME_@SYS_FRAME_UNID');
    var down = `<table style='height:20px;float:left'><tr><td><img height=20 src='/EmpScriptV2/EWA_STYLE/images/file_png/XCEL.png'></td>
                <td><a  href='/static/prj/pf/doc-template/Customer-Leads-Import-Template.xls' target=_blank>导入模板下载.xls</a></td>
                <td><span style='color:#999'>复制粘贴内容需包含表头</span></td>
                </tr></table>`
    tb.find(".EWA_TD_B").prepend(down);


    // 默认自己
    getObj("#SALES_ID").val("@G_ADM_ID");


})();
